5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
