55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	};
68	
69	const INSURANCE_VALUES: Record<string, number> = {
70	  sword: 1000,
71	  amulet: 600,
72	  staff: 800,
73	  potion: 400,
74	  rune: 250,
75	  moonstone: 250,
76	};
77	
78	const DEDUCTIBLE = 100;
79	const CAP_MULTIPLIER = 2;
80	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
81	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
82	
83	const insuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
84	const policyCap = (items: Item[]): number =>
85	  CAP_MULTIPLIER * items.reduce((sum, item) => sum + insuranceValue(item.type), 0);
86	
87	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
88	  rune: 25,
89	  moonstone: 25,
90	};
91	
92	const ITEM_BASE_PREMIUMS: Record<string, number> = {
93	  ...MAIN_ITEM_BASE_PREMIUMS,
94	  ...COMPONENT_BASE_PREMIUMS,
95	};
96	
97	const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
98	const BLOCK_SIZE = 3;
99	const BLOCK_BASE = 60;
100	
101	const CURSE_SURCHARGE_RATE = 0.5;
102	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
103	const HIGH_ENCHANTMENT_THRESHOLD = 5;
104	const LOYALTY_DISCOUNT_RATE = 0.2;
105	const LOYALTY_THRESHOLD_YEARS = 2;
106	const FOLLOWUP_DISCOUNT_RATE = 0.15;
107	
108	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
109	
110	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
111	
112	const componentGroupBase = (count: number, unitBase: number): number => {
113	  if (count === BLOCK_SIZE) return BLOCK_BASE;
114	  return count * unitBase;
115	};
116	
117	const itemSurchargeRate = (item: Item): number => {
118	  let rate = 0;
119	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
120	  if (enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD) {
121	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
122	  }
123	  return rate;
124	};
125	
126	const itemSurcharge = (item: Item, base: number): number =>
127	  base * itemSurchargeRate(item);
128	
129	const policyModifierRate = (customer: Customer, priorQuoteCount: number): number => {
130	  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
131	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
132	    rate -= LOYALTY_DISCOUNT_RATE;
133	  }
134	  if (priorQuoteCount >= 1) {
135	    rate -= FOLLOWUP_DISCOUNT_RATE;
136	  }
137	  return rate;
138	};
139	
140	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
141	
142	const componentsBaseTotal = (components: Item[]): number => {
143	  const counts = new Map<string, number>();
144	  for (const item of components) {
145	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
146	  }
147	  let total = 0;
148	  for (const [type, count] of counts) {
149	    total += componentGroupBase(count, itemBase(type));
150	  }
151	  return total;
152	};
153	
154	const mainItemsBaseTotal = (mainItems: Item[]): number =>
155	  mainItems.reduce((sum, item) => sum + itemBase(item.type), 0);
156	
157	const mainItemsSurchargeTotal = (mainItems: Item[]): number =>
158	  mainItems.reduce((sum, item) => sum + itemSurcharge(item, itemBase(item.type)), 0);
159	
160	const quotePremium = (items: Item[], customer: Customer, priorQuoteCount: number): number => {
161	  const mainItems = items.filter((item) => !isComponent(item));
162	  const components = items.filter(isComponent);
163	
164	  const policyBase = mainItemsBaseTotal(mainItems) + componentsBaseTotal(components);
165	  const itemSurchargeTotal = mainItemsSurchargeTotal(mainItems);
166	  const policyModifierTotal = policyBase * policyModifierRate(customer, priorQuoteCount);
167	
168	  const total = policyBase + itemSurchargeTotal + policyModifierTotal;
169	  return roundUp(total) + PROCESSING_FEE;
170	};
171	
172	const coveredDamageAmount = (insuredItem: Item, damageAmount: number): number => {
173	  if (enchantmentLevel(insuredItem) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
174	    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
175	  }
176	  return damageAmount;
177	};
178	
179	const damagePayout = (damage: Damage, insuredItem: Item): number =>
180	  Math.max(0, coveredDamageAmount(insuredItem, damage.amount) - DEDUCTIBLE);
181	
182	const findInsuredItem = (items: Item[], itemType: string): Item =>
183	  items.find((item) => item.type === itemType) as Item;
184	
185	const totalPayout = (damages: Damage[], items: Item[]): number =>
186	  damages.reduce(
187	    (sum, damage) => sum + damagePayout(damage, findInsuredItem(items, damage.itemType)),
188	    0,
189	  );
190	
191	const policyItems = (scenario: Scenario, policyIndex: number): Item[] =>
192	  (scenario.steps[policyIndex] as QuoteStep).items;
193	
194	const processClaim = (step: ClaimStep, scenario: Scenario): ClaimResult => {
195	  const items = policyItems(scenario, step.policy);
196	  const cap = policyCap(items);
197	  const payout = Math.floor(totalPayout(step.incident.damages, items));
198	  return { payout, remainingCap: cap - payout };
199	};
200	
201	const processStep = (
202	  step: Step,
203	  scenario: Scenario,
204	  priorQuoteCount: number,
205	): StepResult => {
206	  if (step.op === "quote") {
207	    return { premium: quotePremium(step.items, scenario.customer, priorQuoteCount) };
208	  }
209	  return processClaim(step, scenario);
210	};
211	
212	export const processScenario = (scenario: Scenario): ScenarioResult => {
213	  let priorQuoteCount = 0;
214	  const results: StepResult[] = scenario.steps.map((step) => {
215	    const result = processStep(step, scenario, priorQuoteCount);
216	    if (step.op === "quote") priorQuoteCount++;
217	    return result;
218	  });
219	  return { results };
220	};
